import{e as t,c as e,f as s,o as i,_ as r}from"./C5CyrRTP.js";const n={class:"bg-white p-8 lg:p-20"},o=t({__name:"privacy",setup(l){return(d,a)=>(i(),e("div",n,[...a[0]||(a[0]=[s('<div class="max-w-4xl mx-auto space-y-12" data-v-b8f41fa3><div class="space-y-4" data-v-b8f41fa3><h1 class="text-5xl lg:text-7xl text-primary-dark tracking-tighter leading-tight" data-v-b8f41fa3> Privacy statement. </h1><p class="text-lg text-neutral-500 font-medium" data-v-b8f41fa3>Last updated: March 2026</p></div><div class="prose prose-neutral max-w-none space-y-10" data-v-b8f41fa3><section class="space-y-4" data-v-b8f41fa3><h2 class="text-2xl text-primary-dark tracking-tight" data-v-b8f41fa3>1. Introduction</h2><p class="text-neutral-600 leading-relaxed" data-v-b8f41fa3> At Flybeth, we value the trust you place in us as an agent partner. This privacy statement explains how we collect, use, and protect your information and the data of your clients when you use the Flybeth Agent Portal. Our goal is to provide a secure and transparent experience that empowers your travel business. </p></section><section class="space-y-4" data-v-b8f41fa3><h2 class="text-2xl text-primary-dark tracking-tight" data-v-b8f41fa3>2. Information collection</h2><p class="text-neutral-600 leading-relaxed" data-v-b8f41fa3> We collect information necessary to maintain your agency profile and facilitate bookings. This includes: </p><ul class="list-disc pl-6 space-y-2 text-neutral-600" data-v-b8f41fa3><li data-v-b8f41fa3><strong data-v-b8f41fa3>Agency details</strong>: Name, registration numbers, and classification.</li><li data-v-b8f41fa3><strong data-v-b8f41fa3>Contact information</strong>: Names, email addresses, and phone numbers of agents.</li><li data-v-b8f41fa3><strong data-v-b8f41fa3>Transactional data</strong>: Booking records, payment history, and commission data.</li><li data-v-b8f41fa3><strong data-v-b8f41fa3>Client information</strong>: Names and travel preferences strictly for fulfillment purposes.</li></ul></section><section class="space-y-4" data-v-b8f41fa3><h2 class="text-2xl text-primary-dark tracking-tight" data-v-b8f41fa3>3. Data usage</h2><p class="text-neutral-600 leading-relaxed" data-v-b8f41fa3> Your data is used to optimize our service delivery: </p><ul class="list-disc pl-6 space-y-2 text-neutral-600" data-v-b8f41fa3><li data-v-b8f41fa3>Fulfilling global flight and hotel bookings.</li><li data-v-b8f41fa3>Providing real-time analytics and reporting in your dashboard.</li><li data-v-b8f41fa3>Improving platform security and preventing fraudulent activity.</li><li data-v-b8f41fa3>Communicating essential network updates and regional alerts.</li></ul></section><section class="space-y-4" data-v-b8f41fa3><h2 class="text-2xl text-primary-dark tracking-tight" data-v-b8f41fa3>4. Data security</h2><p class="text-neutral-600 leading-relaxed" data-v-b8f41fa3> We employ bank-grade encryption and multi-tiered security protocols to safeguard all information transmitted through our network. Access to sensitive data is strictly controlled and audited to ensure compliance with global data protection standards (such as GDPR and NDPR). </p></section><section class="space-y-4" data-v-b8f41fa3><h2 class="text-2xl text-primary-dark tracking-tight" data-v-b8f41fa3>5. Third-party sharing</h2><p class="text-neutral-600 leading-relaxed" data-v-b8f41fa3> Flybeth only shares data with verified third-party providers (such as airlines, hotel systems, and GDS networks) to the extent necessary to complete a requested booking or transaction. We do not sell your data to marketers. </p></section><section class="space-y-4" data-v-b8f41fa3><h2 class="text-2xl text-primary-dark tracking-tight" data-v-b8f41fa3>6. Contact us</h2><p class="text-neutral-600 leading-relaxed" data-v-b8f41fa3> If you have any questions regarding this privacy statement, please reach out to your regional node manager or contact our compliance team at <a href="mailto:privacy@flybeth.com" class="text-secondary font-bold hover:underline" data-v-b8f41fa3>privacy@flybeth.com</a>. </p></section></div></div>',1)])]))}}),f=r(o,[["__scopeId","data-v-b8f41fa3"]]);export{f as default};
